from pydantic import BaseModel, Field, field_validator
from typing import Literal, Optional
from enum import Enum
import openai
import json

client = openai.OpenAI()

class SupportedIntegration(str, Enum):
    OAUTH2 = "oauth2"
    SAML = "saml"
    API_KEY = "api_key"

class DatabaseQueryParams(BaseModel):
    table_name: str = Field(..., min_length=1, max_length=64)
    limit: int = Field(default=100, ge=1, le=10000)
    order_by: Optional[str] = Field(default=None)
    integration_type: SupportedIntegration

    @field_validator("table_name")
    @classmethod
    def validate_table_name(cls, v: str) -> str:
        allowed_tables = {"users", "orders", "products", "events"}
        if v not in allowed_tables:
            raise ValueError(
                f"Hallucinated table name '{v}'. "
                f"Must be one of: {allowed_tables}"
            )
        return v

def validated_agent_tool_call(user_request: str) -> dict:
    """
    Get structured output from agent and validate before execution.
    """
    response = client.chat.completions.create(
        model="gpt-4o",
        messages=[
            {
                "role": "system",
                "content": (
                    "You are a database query agent. Return a JSON object "
                    "with fields: table_name, limit, order_by, integration_type. "
                    "table_name must be one of: users, orders, products, events. "
                    "integration_type must be one of: oauth2, saml, api_key."
                )
            },
            {"role": "user", "content": user_request}
        ],
        response_format={"type": "json_object"}
    )

    raw_output = json.loads(response.choices[0].message.content)

    try:
        # Validate against schema - raises if hallucinated fields detected
        validated = DatabaseQueryParams(**raw_output)
        return {
            "status": "valid",
            "params": validated.model_dump()
        }
    except Exception as e:
        return {
            "status": "hallucination_detected",
            "error": str(e),
            "raw_output": raw_output
        }

# Example usage
result = validated_agent_tool_call(
    "Query the customer_records table with ldap integration"
)
print(result)
